let chartInstance = null;
Chart.register(ChartDataLabels);
const gradeColors = {
  A: '#5DC987',
  B: '#A3E851',
  C: '#469BC0',
  D: '#888780'
};
function fmtMoney(v) {
  if (v === null || v === undefined || isNaN(v)) return '—';
  return '£' + Number(v).toLocaleString('en-GB', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  });
}
function render(model) {
  const purchase = model.purchaseHistory || [];
  const sale = model.saleHistory || [];
  const trend = model.priceTrend || [];
  const est = model.estimatedValue && model.estimatedValue[0] || null;
  const totalPaidUnits = purchase.reduce((s, r) => s + Number(r.units || 0), 0);
  const weightedPaid = purchase.reduce((s, r) => s + Number(r.avg_paid || 0) * Number(r.units || 0), 0);
  document.getElementById('avgPaid').innerText = totalPaidUnits ? fmtMoney(weightedPaid / totalPaidUnits) : '—';
  const totalSoldUnits = sale.reduce((s, r) => s + Number(r.units_sold || 0), 0);
  const weightedSold = sale.reduce((s, r) => s + Number(r.avg_sold || 0) * Number(r.units_sold || 0), 0);
  document.getElementById('avgSold').innerText = totalSoldUnits ? fmtMoney(weightedSold / totalSoldUnits) : '—';
  if (est && est.sample_size > 0) {
    document.getElementById('estValue').innerText = fmtMoney(est.estimated_value);
    document.getElementById('estValueSub').innerText = 'based on ' + est.sample_size + ' sale' + (est.sample_size == 1 ? '' : 's') + ', this grade';
  } else if (totalSoldUnits > 0) {
    document.getElementById('estValue').innerText = fmtMoney(weightedSold / totalSoldUnits);
    document.getElementById('estValueSub').innerText = 'based on all grades (no exact grade match)';
  } else if (totalPaidUnits > 0) {
    document.getElementById('estValue').innerText = fmtMoney(weightedPaid / totalPaidUnits);
    document.getElementById('estValueSub').innerText = 'based on purchase cost (no sales yet)';
  } else {
    document.getElementById('estValue').innerText = '—';
    document.getElementById('estValueSub').innerText = 'no data';
  }
  const grades = Array.from(new Set([...purchase.map(r => r.grade), ...sale.map(r => r.grade)])).sort();
  const tbody = document.getElementById('gradeTableBody');
  tbody.innerHTML = '';
  if (grades.length === 0) {
    document.getElementById('gradeEmpty').style.display = 'block';
  } else {
    document.getElementById('gradeEmpty').style.display = 'none';
    grades.forEach(g => {
      const p = purchase.find(r => r.grade === g) || {};
      const s = sale.find(r => r.grade === g) || {};
      const color = gradeColors[g] || '#888780';
      const row = document.createElement('tr');
      row.innerHTML = `
        <td><span class="grade-pill" style="background:${color}22; color:${color};">${g || '—'}</span></td>
        <td>${p.units || 0}</td>
        <td>${fmtMoney(p.avg_paid)}</td>
        <td>${s.units_sold || 0}</td>
        <td>${fmtMoney(s.avg_sold)}</td>
      `;
      tbody.appendChild(row);
    });
  }
  renderChart(trend);
}
function renderChart(trend) {
  const canvas = document.getElementById('trendChart');
  const emptyEl = document.getElementById('trendEmpty');
  if (!trend || trend.length === 0) {
    canvas.style.display = 'none';
    emptyEl.style.display = 'block';
    if (chartInstance) {
      chartInstance.destroy();
      chartInstance = null;
    }
    return;
  }
  canvas.style.display = 'block';
  emptyEl.style.display = 'none';
  const months = Array.from(new Set(trend.map(r => r.month))).sort();
  const grades = Array.from(new Set(trend.map(r => r.grade))).sort();
  const datasets = grades.map(g => ({
    label: 'Grade ' + g,
    data: months.map(m => {
      const row = trend.find(r => r.month === m && r.grade === g);
      return row ? Number(row.avg_sold) : null;
    }),
    borderColor: gradeColors[g] || '#469BC0',
    backgroundColor: gradeColors[g] || '#469BC0',
    tension: 0.35,
    spanGaps: true,
    pointRadius: 10,
    pointHoverRadius: 12,
    borderWidth: 2,
    datalabels: {
      color: '#fff',
      font: {
        family: 'Figtree',
        weight: '700',
        size: 9
      },
      formatter: () => g,
      align: 'center',
      anchor: 'center'
    }
  }));
  const labels = months.map(m => new Date(m).toLocaleDateString('en-GB', {
    month: 'short',
    year: '2-digit'
  }));
  if (chartInstance) chartInstance.destroy();
  chartInstance = new Chart(canvas.getContext('2d'), {
    type: 'line',
    data: {
      labels,
      datasets
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: {
          position: 'bottom',
          labels: {
            font: {
              family: 'Figtree',
              size: 11,
              weight: '600'
            },
            color: '#888780',
            boxWidth: 10,
            usePointStyle: true
          }
        },
        tooltip: {
          callbacks: {
            label: ctx => ctx.dataset.label + ': £' + ctx.parsed.y.toFixed(2)
          }
        },
        datalabels: {
          display: true
        }
      },
      scales: {
        x: {
          ticks: {
            font: {
              family: 'Figtree',
              size: 10
            },
            color: '#888780'
          },
          grid: {
            display: false
          }
        },
        y: {
          ticks: {
            font: {
              family: 'Figtree',
              size: 10
            },
            color: '#888780',
            callback: v => '£' + v
          },
          grid: {
            color: 'rgba(0,0,0,0.05)'
          }
        }
      }
    }
  });
}
function initWhenReady() {
  if (typeof appsmith === 'undefined' || !appsmith.onReady) {
    setTimeout(initWhenReady, 50);
    return;
  }
  appsmith.onReady(() => {
    render(appsmith.model);
  });
  appsmith.onModelChange(() => {
    render(appsmith.model);
  });
}
initWhenReady();

